220	// ─── table.move ───────────────────────────────────────────────────────────────
221	
222	/// C: `tmove(L)` — implements `table.move(a1, f, e, t [, a2])`.
223	///
224	/// Copies elements `a1[f..e]` into `a2[t..]` (or `a1[t..]` if `a2` is absent).
225	/// Copies in increasing order when safe, decreasing when ranges overlap.
226	///
227	/// ```c
228	/// static int tmove (lua_State *L) {
229	///   lua_Integer f = luaL_checkinteger(L, 2);
230	///   lua_Integer e = luaL_checkinteger(L, 3);
231	///   lua_Integer t = luaL_checkinteger(L, 4);
232	///   int tt = !lua_isnoneornil(L, 5) ? 5 : 1;
233	///   checktab(L, 1, TAB_R);
234	///   checktab(L, tt, TAB_W);
235	///   if (e >= f) {
236	///     lua_Integer n, i;
237	///     luaL_argcheck(L, f > 0 || e < LUA_MAXINTEGER + f, 3, "too many elements to move");
238	///     n = e - f + 1;
239	///     luaL_argcheck(L, t <= LUA_MAXINTEGER - n + 1, 4, "destination wrap around");
240	///     if (t > e || t <= f || (tt != 1 && !lua_compare(L, 1, tt, LUA_OPEQ))) {
241	///       for (i = 0; i < n; i++) { lua_geti(L, 1, f + i); lua_seti(L, tt, t + i); }
242	///     } else {
243	///       for (i = n - 1; i >= 0; i--) { lua_geti(L, 1, f + i); lua_seti(L, tt, t + i); }
244	///     }
245	///   }
246	///   lua_pushvalue(L, tt);
247	///   return 1;
248	/// }
249	/// ```
250	pub fn tmove(state: &mut LuaState) -> Result<usize, LuaError> {
251	    let f = state.check_arg_integer(2)?;
252	    let e = state.check_arg_integer(3)?;
253	    let t = state.check_arg_integer(4)?;
254	    // C: int tt = !lua_isnoneornil(L, 5) ? 5 : 1
255	    let tt: i32 = if !matches!(state.type_at(5), LuaType::None | LuaType::Nil) {
256	        5
257	    } else {
258	        1
259	    };
260	    check_tab(state, 1, TAB_R)?;
261	    check_tab(state, tt, TAB_W)?;
262	
263	    if e >= f {
264	        // C: luaL_argcheck — overflow guard: e - f + 1 must not overflow i64
265	        if !(f > 0 || e < i64::MAX + f) {
266	            return Err(LuaError::arg_error(3, "too many elements to move"));
267	        }
268	        let n = e - f + 1;
269	        // C: luaL_argcheck — destination end must not overflow
270	        if !(t <= i64::MAX - n + 1) {
271	            return Err(LuaError::arg_error(4, "destination wrap around"));
272	        }
273	        // C: if (t > e || t <= f || (tt != 1 && !lua_compare(L, 1, tt, LUA_OPEQ)))
274	        // Copy forward (increasing) when safe to do so; backward when ranges overlap.
275	        // TODO(port): state.compare(a, b, CompareOp::Eq) → lua_compare LUA_OPEQ; verify method
276	        let copy_forward = t > e
277	            || t <= f
278	            || (tt != 1 && !state.compare(1, tt, CompareOp::Eq)?);
279	        if copy_forward {
280	            for i in 0..n {
281	                state.table_get_i(1, f + i)?;
282	                state.table_set_i(tt, t + i)?;
283	            }
284	        } else {
285	            for i in (0..n).rev() {
286	                state.table_get_i(1, f + i)?;
287	                state.table_set_i(tt, t + i)?;
288	            }
289	        }
290	    }
291	    // C: lua_pushvalue(L, tt) — return the destination table
292	    // TODO(port): state.push_value_at → lua_pushvalue; verify method name
293	    state.push_value_at(tt);
294	    Ok(1)
295	}
